import{_ as d,C as l,o as e,c as i,a2 as r,b as n,w as a,a as s,E as c,a3 as h}from"./chunks/framework.Crpw6aS5.js";const B=JSON.parse('{"title":"配置中心","description":"","frontmatter":{"title":"配置中心","module":"config-center","difficulty":"intermediate","interviewFrequency":"high","tags":["配置中心","Apollo","Nacos Config","微服务","面试高频"],"codeExample":"04-middleware/config-center-examples/src/main/java/com/example/middleware/config/","relatedEntries":["/4-middleware/4.5-registry/","/2-framework/2.3-springcloud/","/2-framework/2.2-springboot/"],"prerequisites":["/2-framework/2.2-springboot/","/2-framework/2.3-springcloud/"],"estimatedTime":"30min"},"headers":[],"relativePath":"4-middleware/4.4-config-center/00-index.md","filePath":"4-middleware/4.4-config-center/00-index.md","lastUpdated":null}'),f={name:"4-middleware/4.4-config-center/00-index.md"};function E(p,t,A,m,g,u){const o=l("Mermaid");return e(),i("div",null,[t[1]||(t[1]=r('<h1 id="配置中心" tabindex="-1">配置中心 <a class="header-anchor" href="#配置中心" aria-label="Permalink to &quot;配置中心&quot;">​</a></h1><h2 id="概念说明" tabindex="-1">概念说明 <a class="header-anchor" href="#概念说明" aria-label="Permalink to &quot;概念说明&quot;">​</a></h2><p>配置中心是微服务架构中的<strong>核心基础设施</strong>，负责集中管理所有微服务的配置信息，实现配置的统一管理、动态更新、环境隔离和安全加密。它解决了微服务架构中&quot;配置分散在各个服务中，修改配置需要重启服务&quot;这一核心问题。</p><p>本模块以 <strong>Apollo</strong> 为主线，系统讲解配置中心的架构设计和核心特性，再对比 Nacos Config 和 Spring Cloud Config，帮助你在面试和工作中做出合理的技术选型。</p><blockquote><p>⚠️ 需要 Apollo 环境的示例，请先启动 Docker：<code>docker compose -f docker/docker-compose.apollo.yml up -d</code></p></blockquote><h2 id="知识点列表" tabindex="-1">知识点列表 <a class="header-anchor" href="#知识点列表" aria-label="Permalink to &quot;知识点列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>序号</th><th>知识点</th><th>难度</th><th>面试频率</th><th>文档链接</th></tr></thead><tbody><tr><td>1</td><td>Apollo 架构设计</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./01-apollo.html">apollo</a></td></tr><tr><td>2</td><td>Nacos Config 使用</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./02-nacos-config.html">nacos-config</a></td></tr><tr><td>3</td><td>配置中心选型对比</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./03-comparison.html">comparison</a></td></tr><tr><td>4</td><td>配置加密与安全</td><td>⭐⭐⭐</td><td>🔥🔥</td><td><a href="./04-security.html">security</a></td></tr><tr><td>5</td><td>配置中心面试指南</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./99-interview.html">interview</a></td></tr></tbody></table><h2 id="推荐学习顺序" tabindex="-1">推荐学习顺序 <a class="header-anchor" href="#推荐学习顺序" aria-label="Permalink to &quot;推荐学习顺序&quot;">​</a></h2>',8)),(e(),n(h,null,{default:a(()=>[c(o,{id:"mermaid-131",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%221.%20Apollo%20%E6%9E%B6%E6%9E%84%E8%AE%BE%E8%AE%A1%3Cbr%2F%3E%E4%B8%89%E5%A4%A7%E7%BB%84%E4%BB%B6%2F%E7%83%AD%E6%9B%B4%E6%96%B0%2F%E7%81%B0%E5%BA%A6%22%5D%20--%3E%20B%5B%222.%20Nacos%20Config%3Cbr%2F%3E%E5%8A%A8%E6%80%81%E5%88%B7%E6%96%B0%2F%E5%A4%9A%E7%8E%AF%E5%A2%83%22%5D%0A%20%20%20%20A%20--%3E%20C%5B%223.%20%E9%85%8D%E7%BD%AE%E4%B8%AD%E5%BF%83%E9%80%89%E5%9E%8B%E5%AF%B9%E6%AF%94%3Cbr%2F%3EApollo%20vs%20Nacos%20vs%20SCC%22%5D%0A%20%20%20%20B%20--%3E%20C%0A%20%20%20%20C%20--%3E%20D%5B%224.%20%E9%85%8D%E7%BD%AE%E5%8A%A0%E5%AF%86%E4%B8%8E%E5%AE%89%E5%85%A8%3Cbr%2F%3EJasypt%2FVault%22%5D%0A%20%20%20%20D%20--%3E%20E%5B%225.%20%E9%9D%A2%E8%AF%95%E6%8C%87%E5%8D%97%E6%B1%87%E6%80%BB%22%5D%0A%0A%20%20%20%20style%20A%20fill%3A%23e1f5fe%0A%20%20%20%20style%20B%20fill%3A%23e1f5fe%0A%20%20%20%20style%20C%20fill%3A%23fff3e0%0A%20%20%20%20style%20D%20fill%3A%23f3e5f5%0A%20%20%20%20style%20E%20fill%3A%23e8f5e9%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=r('<p><strong>学习路线说明</strong>：</p><ul><li>🔵 <strong>核心方案层</strong>（1-2）：深入 Apollo 架构，了解 Nacos Config</li><li>🟠 <strong>选型决策层</strong>（3）：对比三种方案的优劣</li><li>🟣 <strong>安全实践层</strong>（4）：配置加密和安全管理</li><li>🟢 <strong>面试汇总</strong>（5）：高频面试题和追问链路</li></ul><h2 id="为什么需要配置中心" tabindex="-1">为什么需要配置中心？ <a class="header-anchor" href="#为什么需要配置中心" aria-label="Permalink to &quot;为什么需要配置中心？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>传统方式</th><th>配置中心方案</th></tr></thead><tbody><tr><td>配置分散</td><td>每个服务各自维护配置文件</td><td>集中管理，统一入口</td></tr><tr><td>修改需重启</td><td>改配置 → 打包 → 部署 → 重启</td><td>热更新，秒级生效</td></tr><tr><td>环境管理</td><td>手动维护多套配置文件</td><td>环境隔离，一键切换</td></tr><tr><td>安全风险</td><td>敏感配置明文存储在代码仓库</td><td>加密存储，权限控制</td></tr><tr><td>版本追溯</td><td>无法追踪配置变更历史</td><td>版本管理，一键回滚</td></tr><tr><td>灰度发布</td><td>无法针对部分实例灰度配置</td><td>灰度发布，精准推送</td></tr></tbody></table><h2 id="相关模块链接" tabindex="-1">相关模块链接 <a class="header-anchor" href="#相关模块链接" aria-label="Permalink to &quot;相关模块链接&quot;">​</a></h2><ul><li><a href="/4-middleware/4.5-registry/">注册中心</a> — Consul KV 也可作为简单配置中心</li><li><a href="/2-framework/2.3-springcloud/">Spring Cloud</a> — 微服务框架集成</li><li><a href="/2-framework/2.2-springboot/">Spring Boot</a> — 配置文件体系基础</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://www.apolloconfig.com/" target="_blank" rel="noreferrer">Apollo 官方文档</a></li><li><a href="https://nacos.io/docs/latest/guide/user/open-api/" target="_blank" rel="noreferrer">Nacos Config 文档</a></li><li><a href="https://docs.spring.io/spring-cloud-config/reference/" target="_blank" rel="noreferrer">Spring Cloud Config 文档</a></li></ul>',8))])}const _=d(f,[["render",E]]);export{B as __pageData,_ as default};
